public void setView(View view, ViewGroup.LayoutParams attrs, ...) {
    synchronized (this) {
        // 1. 保存 DecorView 引用
        mView = view;

        // 2. 通过 IWindowSession 向 WMS 添加窗口
        res = mWindowSession.addToDisplay(mWindow, seq, mWindowAttributes,
            getHostVisibility(), ..., mInputChannel, mTempInsets);

        // 3. 发起首次布局请求
        requestLayout();
    }
}
